// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getRides,
  getApprovedCaptains,
  getPendingCaptains,
} from "../../services/adminApi";
import {
  Paper,
  Typography,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  CircularProgress,
  Box,
} from "@mui/material";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({
    users: 0,
    riders: 0,
    captains: 0,
    pendingCaptains: 0,
    rides: 0,
  });
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const [overviewRes, ridesRes, approvedRes, pendingRes] = await Promise.all([
          getOverview(),
          getRides(),
          getApprovedCaptains(),
          getPendingCaptains(),
        ]);

        setOverview({
          users: overviewRes.data.users || 0,
          riders: overviewRes.data.riders || 0,
          captains: approvedRes.data.captains?.length || 0,
          pendingCaptains: pendingRes.data.pendingCaptains?.length || 0,
          rides: overviewRes.data.rides || 0,
        });

        setRides(ridesRes.data.rides || []);
      } catch (err) {
        console.error("Admin Dashboard API error:", err);
        setError("Failed to fetch dashboard data.");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  if (loading)
    return (
      <Box display="flex" justifyContent="center" mt={5}>
        <CircularProgress />
      </Box>
    );

  if (error)
    return (
      <Typography color="error" align="center" mt={5}>
        {error}
      </Typography>
    );

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Admin Dashboard
      </Typography>

      <Paper sx={{ p: 2, mb: 3 }}>
        <Typography>Users: {overview.users}</Typography>
        <Typography>Riders: {overview.riders}</Typography>
        <Typography>Approved Captains: {overview.captains}</Typography>
        <Typography>Pending Captains: {overview.pendingCaptains}</Typography>
        <Typography>Total Rides: {overview.rides}</Typography>
      </Paper>

      <Paper sx={{ p: 2 }}>
        <Typography variant="h6" gutterBottom>
          Recent Rides
        </Typography>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Rider</TableCell>
              <TableCell>Captain</TableCell>
              <TableCell>Pickup</TableCell>
              <TableCell>Drop</TableCell>
              <TableCell>Fare</TableCell>
              <TableCell>Status</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {rides.length === 0 ? (
              <TableRow>
                <TableCell colSpan={6} align="center">
                  No rides found
                </TableCell>
              </TableRow>
            ) : (
              rides.map((ride) => (
                <TableRow key={ride._id}>
                  <TableCell>{ride.riderId?.fullName || "-"}</TableCell>
                  <TableCell>{ride.captainId?.fullName || "-"}</TableCell>
                  <TableCell>{ride.pickup || "-"}</TableCell>
                  <TableCell>{ride.drop || "-"}</TableCell>
                  <TableCell>{ride.fare ?? "-"}</TableCell>
                  <TableCell>{ride.status || "-"}</TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </Paper>
    </Box>
  );
}
